<?php
declare(strict_types=1);
require_once __DIR__.'/../../includes/ecosystem.php';
$wallet=beyond_app_bootstrap('Beyond Wallet');
global $pdo;
$transactions=[];
try{$stmt=$pdo->prepare('SELECT t.* FROM beyond_wallet_transactions t JOIN beyond_wallets w ON w.id=t.wallet_id WHERE w.user_id=? ORDER BY t.created_at DESC LIMIT 50');$stmt->execute([(int)$_SESSION['user_id']]);$transactions=$stmt->fetchAll(PDO::FETCH_ASSOC);}catch(Throwable $e){}
$earned=0.0;$spent=0.0;
foreach($transactions as $item){$amount=(float)($item['amount']??0);if(($item['type']??'')==='credit')$earned+=abs($amount);else $spent+=abs($amount);}
$balance=(float)($wallet['balance']??0);
?><!doctype html><html lang="en"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><meta name="theme-color" content="#171025"><title>Beyond Wallet | Beyond OS 2.2.1</title><link rel="stylesheet" href="../assets/css/admin-v2.css?v=2.3.1"><style>
.wallet-page{max-width:1180px;margin:auto}.wallet-hero{position:relative;overflow:hidden;display:grid;grid-template-columns:minmax(0,1.2fr) minmax(260px,.8fr);gap:28px;align-items:end;padding:clamp(28px,5vw,54px);background:radial-gradient(circle at 86% 12%,#fd5e9b55,transparent 32%),linear-gradient(135deg,#28205d,#762678 58%,#bd326f);color:#fff}.wallet-hero:after{position:absolute;right:-80px;bottom:-120px;width:330px;height:330px;border:1px solid #ffffff22;border-radius:50%;content:""}.wallet-balance h1{font-size:clamp(52px,8vw,86px);margin:12px 0 7px;letter-spacing:-.065em;line-height:.9}.wallet-balance p{max-width:560px;margin:18px 0 0;color:#f1deee}.balance-mark{font-size:clamp(62px,8vw,102px);font-weight:950;text-align:right;opacity:.28;letter-spacing:-.08em}.metric-grid{display:grid;grid-template-columns:repeat(4,minmax(0,1fr));gap:14px;margin-top:16px}.metric{padding:20px;border:1px solid var(--border);border-radius:18px;background:var(--panel);box-shadow:var(--shadow-soft)}.metric small{display:block;color:var(--muted);font-weight:800;text-transform:uppercase;letter-spacing:.09em}.metric strong{display:block;margin-top:9px;font-size:clamp(21px,3vw,30px)}.market-layout{display:grid;grid-template-columns:minmax(0,1.45fr) minmax(270px,.55fr);gap:16px;margin-top:16px}.market-card{min-width:0}.market-head{display:flex;align-items:flex-start;justify-content:space-between;gap:18px}.market-title{display:flex;align-items:center;gap:12px}.btc-mark{display:grid;width:45px;height:45px;place-items:center;border-radius:50%;background:#f7931a;color:#fff;font-size:24px;font-weight:900}.market-price{font-size:clamp(30px,4vw,46px);font-weight:900;letter-spacing:-.045em}.market-sub{color:var(--muted)}.change{display:inline-flex;margin-top:6px;padding:5px 9px;border-radius:999px;font-size:12px;font-weight:850}.change.up{background:var(--good-soft);color:var(--good)}.change.down{background:var(--bad-soft);color:var(--bad)}.chart-wrap{position:relative;height:270px;margin-top:22px}.chart-wrap canvas{width:100%;height:100%}.chart-status{position:absolute;inset:0;display:grid;place-items:center;color:var(--muted)}.chart-status[hidden]{display:none}.compare{display:grid;gap:12px}.compare-row{padding:17px;border:1px solid var(--border);border-radius:16px;background:var(--panel2)}.compare-row span,.compare-row strong{display:block}.compare-row span{color:var(--muted);font-size:12px}.compare-row strong{margin-top:5px;font-size:20px}.disclaimer{padding:14px;border-radius:14px;background:var(--accent-soft);color:var(--muted);font-size:12px;line-height:1.5}.activity-card{margin-top:16px}.receipt{display:flex;justify-content:space-between;gap:12px;padding:15px 0;border-bottom:1px solid var(--border)}.receipt:last-child{border-bottom:0}.empty-actions{display:flex;gap:10px;flex-wrap:wrap;margin-top:18px}.source-note{margin:10px 0 0;color:var(--muted);font-size:11px}
