<section class="card wallet-hero"><div class="wallet-balance"><span class="badge">BEYOND BITS</span><h1><?=number_format($balance,0)?> <?=e((string)($wallet['currency']??'BITS'))?></h1><p>Your reward balance follows your Beyond ID across every connected app.</p></div><div class="balance-mark">bit$</div></section>
