<section class="card activity-card"><div class="card-heading"><h2>Wallet activity</h2><span class="badge"><?=count($transactions)?> entries</span></div><?php if(!$transactions):?><p class="muted">No wallet activity yet. Complete your profile to earn your first 100 bit$.</p><div class="empty-actions"><a class="btn" href="profile.php">Complete profile</a><a class="btn btn-secondary" href="/app-store/">Explore earning apps</a></div><?php endif;?><?php foreach($transactions as $item):?><div class="receipt"><span><?=e((string)($item['description']?:$item['app_slug']))?><br><small class="muted"><?=e((string)$item['created_at'])?></small></span><strong><?=$item['type']==='credit'?'+':'−'?><?=number_format(abs((float)$item['amount']),0)?> bit$</strong></div><?php endforeach;?></section>
</main><script>
(()=>{const usd=document.getElementById('btcUsd'),cad=document.getElementById('btcCad'),change=document.getElementById('btcChange'),move=document.getElementById('btcMove'),canvas=document.getElementById('btcChart'),status=document.getElementById('chartStatus');let points=[];const money=(n,c)=>new Intl.NumberFormat('en-CA',{style:'currency',currency:c,maximumFractionDigits:0}).format(n);function draw(){const dpr=devicePixelRatio||1,w=canvas.clientWidth,h=canvas.clientHeight;canvas.width=w*dpr;canvas.height=h*dpr;const c=canvas.getContext('2d');c.scale(dpr,dpr);c.clearRect(0,0,w,h);if(points.length<2)return;const vals=points.map(p=>p[1]),min=Math.min(...vals),max=Math.max(...vals),pad=16,range=max-min||1;c.beginPath();points.forEach((p,i)=>{const x=pad+i*(w-pad*2)/(points.length-1),y=h-pad-(p[1]-min)*(h-pad*2)/range;i?c.lineTo(x,y):c.moveTo(x,y)});const g=c.createLinearGradient(0,0,w,0);g.addColorStop(0,'#7659ef');g.addColorStop(1,'#f04f9c');c.strokeStyle=g;c.lineWidth=3;c.stroke();c.lineTo(w-pad,h-pad);c.lineTo(pad,h-pad);c.closePath();const fill=c.createLinearGradient(0,0,0,h);fill.addColorStop(0,'rgba(118,89,239,.28)');fill.addColorStop(1,'rgba(118,89,239,0)');c.fillStyle=fill;c.fill()}async function load(){try{const [p,h]=await Promise.all([fetch('https://api.coingecko.com/api/v3/simple/price?ids=bitcoin&vs_currencies=usd,cad&include_24hr_change=true',{cache:'no-store'}),fetch('https://api.coingecko.com/api/v3/coins/bitcoin/market_chart?vs_currency=usd&days=7',{cache:'no-store'})]);if(!p.ok||!h.ok)throw Error('Market feed unavailable');const price=(await p.json()).bitcoin,history=await h.json();points=history.prices||[];usd.textContent=money(price.usd,'USD');cad.textContent=money(price.cad,'CAD');const n=Number(price.usd_24h_change||0),label=(n>=0?'+':'')+n.toFixed(2)+'%';change.textContent=label+' today';move.textContent=label;change.className='change '+(n>=0?'up':'down');status.hidden=true;draw()}catch(e){usd.textContent='Unavailable';change.textContent='Try again soon';change.className='change';status.textContent='Live market data is temporarily unavailable.'}}load();setInterval(load,60000);addEventListener('resize',draw)})();
</script></body></html>
